               osi_WrStrLn(" -n <[-]Hz> <[-]Hz> notchfilter baseband from to Hz (may be repeatet)", 70ul);
               osi_WrStrLn(" -O <0..1>          (*)optimize on off else automatic on sf/bw (-1)", 68ul);
               osi_WrStrLn(" -o <Hz>            shift input iq band +-Hz", 45ul);
